const config = $('Load Config').first().json;
const reddit = $('Fetch Reddit n8n').first().json;
const newsXml = $('Fetch Google News RSS').first().json?.data || '';

const redditTopics = [];
try {
  const posts = reddit?.data?.children || [];
  for (const p of posts) {
    const title = p?.data?.title;
    if (title && title.length > 15) {
      redditTopics.push({ topic: title.replace(/\[.*?\]/g, '').trim(), source: 'reddit', score: p.data.ups || 0 });
    }
  }
} catch (e) { /* reddit parse fail ok */ }

const newsTopics = [];
const titleRegex = /<title><!\[CDATA\[(.*?)\]\]><\/title>/g;
let m;
while ((m = titleRegex.exec(newsXml)) !== null) {
  const t = m[1];
  if (t && !t.includes('Google News') && t.length > 20) {
    newsTopics.push({ topic: t.trim(), source: 'news', score: 50 });
  }
}

const combined = [...redditTopics, ...newsTopics]
  .sort((a, b) => b.score - a.score)
  .slice(0, 40);

return [{ json: { ...config, rawTopics: combined, rawCount: combined.length } }];

